  // Check response
  if httpResp.StatusCode == 200 {
    fmt.Printf("✅ Send successful! Status: %d\n", httpResp.StatusCode)
    if response != nil {
      fmt.Printf("Message ID: %s\n", *response.Data[0].ID)
    }
  } else {
    fmt.Printf("❌ Unexpected status code: %d\n", httpResp.StatusCode)
  }
